function compareItemsInSameGroup(a: ModuleSettingCatalogItem, b: ModuleSettingCatalogItem): number {
  if (a.groupKey !== b.groupKey) return 0;
  const oa = MODULE_SETTINGS_INTRA_SORT[a.seq];
  const ob = MODULE_SETTINGS_INTRA_SORT[b.seq];
  const hasA = oa !== undefined;
  const hasB = ob !== undefined;
  if (hasA && hasB && oa !== ob) return oa - ob;
  if (hasA !== hasB) return hasA ? -1 : 1;
  return a.seq - b.seq;
}

export function groupCatalogItemsByCategory(
  items: ModuleSettingCatalogItem[],
  groupOrder?: string[],
): ModuleSettingCatalogGroup[] {
  const discovered: string[] = [];
  const map = new Map<string, ModuleSettingCatalogItem[]>();
  for (const item of items) {
    if (!map.has(item.groupKey)) {
      map.set(item.groupKey, []);
      discovered.push(item.groupKey);
    }
    map.get(item.groupKey)!.push(item);
  }
  const order =
    groupOrder && groupOrder.length > 0
      ? [
          ...groupOrder.filter((k) => map.has(k)),
          ...discovered.filter((k) => !groupOrder.includes(k)),
        ]
      : discovered;
  return order.map((groupKey) => {
    const groupItems = map.get(groupKey)!.slice().sort(compareItemsInSameGroup);
    return { groupKey, groupTitle: groupItems[0]?.groupTitle ?? groupKey, items: groupItems };
  });
}

/** 按 seq 从全部 hub 中解析设置项（团队等业务页嵌入用） */
export function getTeamEmbeddedSettingItems(seqs: readonly number[]): ModuleSettingCatalogItem[] {
  const want = new Set(seqs);
  const bySeq = new Map<number, ModuleSettingCatalogItem>();
  for (const hub of Object.values(MODULE_SETTINGS_BY_PATH)) {
    for (const item of hub.items) {
      if (want.has(item.seq) && !bySeq.has(item.seq)) bySeq.set(item.seq, item);
    }
  }
  return seqs
    .map((seq) => bySeq.get(seq))
    .filter((item): item is ModuleSettingCatalogItem => item !== undefined);
}
